<?php
namespace Tests\Feature;use App\Models\CharacterItem;use App\Models\CharacterWallet;use App\Models\GoldTransaction;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;class GenerateMonsterLootCommandTest extends TestCase{use RefreshDatabase;public function test_command_and_no_rewards(){$this->seed(WorldCatalogSeeder::class);$this->artisan('game:loot:generate',['monsterCode'=>'grey_wolf','--times'=>2])->assertExitCode(0);$this->assertSame(0,CharacterItem::count());$this->assertSame(0,CharacterWallet::count());$this->assertSame(0,GoldTransaction::count());}public function test_invalid_inputs(){$this->artisan('game:loot:generate',['monsterCode'=>'none'])->assertExitCode(1);$this->artisan('game:loot:generate',['monsterCode'=>'none','--times'=>101])->assertExitCode(1);}}
